const tz = "America/Toronto";
const yDate = new Date(Date.now() - 24 * 3600 * 1000);
const iso = new Intl.DateTimeFormat("en-CA", { timeZone: tz, year: "numeric", month: "2-digit", day: "2-digit" }).format(yDate);
const nice = new Intl.DateTimeFormat("en-CA", { timeZone: tz, weekday: "long", month: "long", day: "numeric", year: "numeric" }).format(yDate);
const short = new Intl.DateTimeFormat("en-CA", { timeZone: tz, month: "long", day: "numeric" }).format(yDate);
const safe = (name) => { try { const j = $(name).first().json; return Array.isArray(j.results) ? j.results : []; } catch (e) { return []; } };
const stats = safe("Fetch Campaign Stats");
const convs = safe("Fetch Conversions");
const callsAll = safe("Fetch Calls");
const formsAll = safe("Fetch Lead Form Submissions");
const money = (m) => Number(m || 0) / 1e6;
const dollars = (v) => "$" + v.toFixed(2);
const plural = (n, w) => n + " " + w + (Number(n) === 1 ? "" : "s");
let spend = 0, clicks = 0;
const statRows = stats.map(r => { const c = money(r.metrics.costMicros); spend += c; clicks += Number(r.metrics.clicks || 0); return { name: r.campaign.name, impr: r.metrics.impressions, clicks: r.metrics.clicks, cost: c }; });
const calls = callsAll.filter(r => (r.callView.startCallDateTime || "").startsWith(iso));
const missed = calls.filter(r => r.callView.callStatus === "MISSED" || Number(r.callView.callDurationSeconds || 0) < 30);
const answered = calls.length - missed.length;
const forms = formsAll.filter(r => ((r.leadFormSubmissionData || {}).submissionDateTime || "").startsWith(iso));
const UNTRACKED = ["Contact Us", "Phone Click"];
const convRows = convs.map(r => { const n = Number(r.metrics.allConversions || 0); const action = r.segments.conversionActionName; const isRef = UNTRACKED.some(u => action.indexOf(u) === 0); return { campaign: r.campaign.name, action: action, n: n, isRef: isRef }; });
const verified = convRows.filter(r => !r.isRef).reduce((a, r) => a + r.n, 0);
const esc = (s) => String(s || "").replace(/&/g, "&amp;").replace(/</g, "&lt;");
const td = "padding:7px 10px;border-bottom:1px solid #e8e8e8;vertical-align:top";
const th = (t) => "<th align=\"left\" style=\"padding:7px 10px;background:#F5F7FA;color:#0D1B2A;font-size:12px;letter-spacing:0.4px;border-bottom:2px solid #C9A84C\">" + t + "</th>";
const callRow = (r) => {
  const v = r.callView;
  const time = (v.startCallDateTime || "").slice(11, 16);
  const dur = Number(v.callDurationSeconds || 0);
  let label, color;
  if (v.callStatus === "MISSED") { label = "Missed. Worth a callback today"; color = "#B42318"; }
  else if (dur < 30) { label = "Ended after " + plural(dur, "second"); color = "#B42318"; }
  else { label = "Answered, " + plural(dur, "second"); color = "#1B7F3B"; }
  const caller = v.callerAreaCode ? "(" + v.callerAreaCode + ") number" : "Number unavailable";
  return "<tr><td style=\"" + td + "\">" + time + "</td><td style=\"" + td + "\">" + caller + "</td><td style=\"" + td + ";color:" + color + "\">" + label + "</td><td style=\"" + td + ";color:#6B7280\">" + esc(r.campaign.name) + "</td></tr>";
};
let html = "<div style=\"font-family:Arial,sans-serif;max-width:640px;margin:0 auto;color:#1F2937\">";
html += "<table cellspacing=\"0\" cellpadding=\"0\" style=\"width:100%;background:#0D1B2A\"><tr><td style=\"padding:12px 16px\"><span style=\"color:#C9A84C;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;letter-spacing:4px\">STENTH</span></td><td align=\"right\" style=\"padding:12px 16px\"><span style=\"color:#ffffff;font-family:Arial,sans-serif;font-size:12px;letter-spacing:1px\">Daily Performance Report</span></td></tr></table>";
html += "<h2 style=\"margin:18px 0 2px;color:#0D1B2A\">Blottman Legal Services</h2>";
html += "<p style=\"margin:0 0 14px;color:#6B7280;font-size:13px\">Advertising results for " + nice + "</p>";
html += "<div style=\"background:#F5F7FA;border-radius:8px;padding:14px 16px;font-size:15px;line-height:1.7\">";
html += "<b>Spend</b> " + dollars(spend) + " &nbsp;&middot;&nbsp; <b>Clicks</b> " + clicks + " &nbsp;&middot;&nbsp; <b>Calls</b> " + calls.length + " (" + answered + " answered, " + missed.length + " missed or short) &nbsp;&middot;&nbsp; <b>Verified leads</b> " + verified;
html += "</div>";
if (missed.length > 0) {
  html += "<p style=\"background:#FEF2F2;border-left:4px solid #B42318;padding:12px 14px;font-size:14px;line-height:1.6\"><b>" + plural(missed.length, "call") + " went unanswered or lasted under 30 seconds yesterday.</b> These callers have already been paid for. A callback today can still turn them into clients.</p>";
}
if (calls.length > 0) {
  html += "<h3 style=\"color:#0D1B2A;margin:20px 0 6px;font-size:15px\">Phone calls</h3><table cellspacing=\"0\" style=\"width:100%;font-size:13px;border-collapse:collapse\"><tr>" + th("Time") + th("Caller") + th("Outcome") + th("Campaign") + "</tr>" + calls.map(callRow).join("") + "</table>";
}
if (forms.length > 0) {
  html += "<h3 style=\"color:#0D1B2A;margin:20px 0 6px;font-size:15px\">Lead form submissions</h3>";
  forms.forEach(f => {
    const flds = ((f.leadFormSubmissionData || {}).leadFormSubmissionFields || []).map(x => esc(x.fieldType) + ": " + esc(x.fieldValue)).join(" &middot; ");
    html += "<p style=\"font-size:13px;background:#F5F7FA;padding:10px 12px;border-radius:6px\">" + flds + " <span style=\"color:#6B7280\">(" + esc(f.campaign.name) + ")</span></p>";
  });
  html += "<p style=\"color:#6B7280;font-size:12px\">These submissions are saved automatically. Google would otherwise delete them after 30 days.</p>";
}
if (convRows.length > 0) {
  html += "<h3 style=\"color:#0D1B2A;margin:20px 0 6px;font-size:15px\">Conversions recorded</h3><table cellspacing=\"0\" style=\"width:100%;font-size:13px;border-collapse:collapse\"><tr>" + th("Action") + th("Campaign") + th("Count") + "</tr>" + convRows.map(r => "<tr><td style=\"" + td + "\">" + esc(r.action) + (r.isRef ? " <span style=\"color:#6B7280\">(for reference, not a verified lead)</span>" : "") + "</td><td style=\"" + td + ";color:#6B7280\">" + esc(r.campaign) + "</td><td style=\"" + td + "\">" + r.n + "</td></tr>").join("") + "</table>";
}
html += "<h3 style=\"color:#0D1B2A;margin:20px 0 6px;font-size:15px\">Campaign spend</h3><table cellspacing=\"0\" style=\"width:100%;font-size:13px;border-collapse:collapse\"><tr>" + th("Campaign") + th("Impressions") + th("Clicks") + th("Cost") + "</tr>" + statRows.map(r => "<tr><td style=\"" + td + "\">" + esc(r.name) + "</td><td style=\"" + td + "\">" + r.impr + "</td><td style=\"" + td + "\">" + r.clicks + "</td><td style=\"" + td + "\">" + dollars(r.cost) + "</td></tr>").join("") + "</table>";
html += "<p style=\"color:#6B7280;font-size:11px;margin-top:22px;border-top:1px solid #e8e8e8;padding-top:10px\">Prepared automatically each morning by Stenth for Blottman Legal Services. Google Ads account 858 621 4705.</p></div>";
const subject = "Stenth daily report, " + short + ": " + dollars(spend) + " spent, " + plural(calls.length, "call") + ", " + plural(verified, "verified lead");
return [{ json: { subject: subject, html: html, date: iso } }];
